1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;
3	
4	const applyFirstInsuranceSurcharge = (premium: number): number =>
5	  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const CURSED_SURCHARGE_RATE = 1 / 2;
17	
18	const COMPONENT_TYPES = ["rune", "moonstone"];
19	const BLOCK_SIZE = 3;
20	const BLOCK_PREMIUM = 60;
21	
22	const HIGHLY_ENCHANTED_THRESHOLD = 5;
23	const ENCHANTMENT_SURCHARGE_RATE = 3 / 10;
24	
25	type Item = { type: string; enchantment?: number; cursed?: boolean };
26	
27	const isComponent = (item: Item): boolean =>
28	  COMPONENT_TYPES.includes(item.type);
29	
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_THRESHOLD;
32	
33	const calculateItemPremium = (item: Item): number => {
34	  const basePremium = BASE_PREMIUMS[item.type] ?? 0;
35	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
36	  const enchantmentSurcharge = isHighlyEnchanted(item)
37	    ? basePremium * ENCHANTMENT_SURCHARGE_RATE
38	    : 0;
39	  return applyFirstInsuranceSurcharge(basePremium) + cursedSurcharge + enchantmentSurcharge;
40	};
41	
42	export const quote = (items: Item[], customer: unknown, contractNumber: number): number => {
43	  const componentCounts: Record<string, number> = {};
44	  for (const item of items) {
45	    if (isComponent(item)) {
46	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
47	    }
48	  }
49	
50	  let totalPremium = 0;
51	
52	  for (const item of items) {
53	    if (isComponent(item) && componentCounts[item.type] === BLOCK_SIZE) {
54	      continue;
55	    }
56	    totalPremium += calculateItemPremium(item);
57	  }
58	
59	  for (const type of COMPONENT_TYPES) {
60	    if (componentCounts[type] === BLOCK_SIZE) {
61	      totalPremium += applyFirstInsuranceSurcharge(BLOCK_PREMIUM);
62	    }
63	  }
64	
65	  return Math.ceil(totalPremium) + PROCESSING_FEE;
66	};
67	
68	export function claim(): unknown {
69	  return undefined;
70	}
